package com.companionlink.servlet.volunteer;
import com.companionlink.dao.RequestDAO; import com.companionlink.servlet.BaseServlet; import jakarta.servlet.*; import jakarta.servlet.annotation.WebServlet; import jakarta.servlet.http.*; import java.io.IOException;
@WebServlet("/volunteer/requests") public class VolunteerRequestsServlet extends BaseServlet { private final RequestDAO dao=new RequestDAO(); protected void doGet(HttpServletRequest r,HttpServletResponse h)throws ServletException,IOException{r.setAttribute("keyword",r.getParameter("q"));r.setAttribute("requests",dao.findOpen(r.getParameter("q")));forward(r,h,"volunteer/requests");} protected void doPost(HttpServletRequest r,HttpServletResponse h)throws IOException{dao.acceptRequest(Integer.parseInt(r.getParameter("requestId")),currentUser(r).getId());ok(r,h,"/volunteer/schedule","Request accepted and added to your schedule.");}}
